import { useState, useEffect, useCallback } from 'react'
import { Box, Button, Group, Modal, Text, TextInput } from '@mantine/core'
import { notifications } from '@mantine/notifications'
import ThumbnailPanel from './ThumbnailPanel'
import DetailPanel from '../DetailPanel'
import { OpenFile, OpenPDF, PageCount, PickFolder, ExportSplit } from '../../../wailsjs/go/main/App'
import { basename } from '../../utils'
import { useOutputFiles } from './useOutputFiles'

const DEFAULT_TEMPLATE = '{date} {name}'

function applyTemplate(template: string): { value: string; cursorPos: number } {
  const date = new Date().toISOString().split('T')[0]
  const withDate = template.replace('{date}', date)
  const nameIdx = withDate.indexOf('{name}')
  if (nameIdx === -1) return { value: withDate, cursorPos: withDate.length }
  return { value: withDate.replace('{name}', ''), cursorPos: nameIdx }
}

// Tracks which filename input should steal focus after a split point is added,
// and where the cursor should land within it. Cleared by the input itself once
// it has focused, so only the first render after the split point is added fires.
function usePendingFocus() {
  const [pendingFocus, setPendingFocus] = useState<{ afterPage: number; cursorPos: number } | null>(null)
  const request = useCallback((afterPage: number, cursorPos: number) => setPendingFocus({ afterPage, cursorPos }), [])
  const clear = useCallback(() => setPendingFocus(null), [])
  return { pendingFocus, request, clear }
}

interface Props {
  initialPath?: string | null
}

export default function SplitMode({ initialPath }: Props) {
  const [pdfPath, setPdfPath] = useState<string | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [selectedPage, setSelectedPage] = useState(1)
  const [outputFolder, setOutputFolder] = useState<string | null>(null)
  const [successModal, setSuccessModal] = useState<{show: boolean, path: string}>({show: false, path: ''})
  const outputFiles = useOutputFiles()
  const focus = usePendingFocus()
  const [template, setTemplate] = useState(DEFAULT_TEMPLATE)
  const [exporting, setExporting] = useState(false)

  const resetForFile = (count: number, path: string, tmpl: string) => {
    setPdfPath(path)
    setPageCount(count)
    setSelectedPage(1)
    outputFiles.reset(applyTemplate(tmpl).value)
    focus.clear()
  }

  useEffect(() => {
    if (!initialPath) return
    PageCount(initialPath)
      .then(count => resetForFile(count, initialPath, template))
      .catch(e => notifications.show({ title: 'Failed to open file', message: String(e), color: 'red' }))
  }, [initialPath])

  const handleOpen = async () => {
    const path = await OpenPDF()
    if (!path) return
    try {
      const count = await PageCount(path)
      resetForFile(count, path, template)
    } catch (e) {
      notifications.show({ title: 'Failed to open file', message: String(e), color: 'red' })
    }
  }

  const handlePickOutputFolder = async () => {
    const folder = await PickFolder()
    if (folder) setOutputFolder(folder)
  }

  const handleExport = async () => {
    if (!pdfPath || !outputFolder) return
    setExporting(true)
    try {
      const files = [...outputFiles.all.entries()]
        .sort(([a], [b]) => a - b)
        .map(([firstPage, file]) => ({
          firstPage,
          name: file.name,
          outDir: file.folderOverride ?? outputFolder,
        }))
      await ExportSplit(pdfPath, files)
      setSuccessModal({show: true, path: outputFolder})
    } catch (e) {
      notifications.show({ title: 'Export failed', message: String(e), color: 'red' })
    } finally {
      setExporting(false)
    }
  }

  const handleToggleSplitPoint = useCallback((afterPage: number) => {
    const prefill = applyTemplate(template)
    const added = outputFiles.toggle(afterPage, prefill.value)
    if (added) focus.request(afterPage, prefill.cursorPos)
    else focus.clear()
  }, [template, outputFiles.toggle])

  return (
    <Box style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <Modal opened={successModal.show} onClose={() => setSuccessModal({show: false, path: ''})} title="Export complete" centered>
        <Text size="sm" c="dimmed" mb="md">{successModal.path}</Text>
        <Button variant="default" onClick={() => OpenFile(successModal.path!)}>
          Open in Finder
        </Button>
      </Modal>
      <Box
        style={{
          flexShrink: 0,
          borderBottom: '1px solid var(--mantine-color-gray-3)',
          display: 'flex',
          alignItems: 'center',
          paddingInline: 12,
          height: 44,
        }}
      >
        <Group gap={8} style={{ width: '100%' }}>
          <Button size="xs" variant="default" onClick={handleOpen}>
            Open PDF
          </Button>
          <TextInput
            size="xs"
            placeholder={DEFAULT_TEMPLATE}
            value={template}
            onChange={(e) => setTemplate(e.currentTarget.value)}
            leftSection={<span style={{ fontSize: 11, whiteSpace: 'nowrap', color: 'var(--mantine-color-dimmed)' }}>Template</span>}
            leftSectionWidth={60}
            style={{ flex: 1 }}
          />
          <Button size="xs" variant="default" onClick={handlePickOutputFolder}>
            {outputFolder ? basename(outputFolder) : 'Output folder…'}
          </Button>
          <Button size="xs" disabled={!pdfPath || !outputFolder} loading={exporting} onClick={handleExport}>
            Export
          </Button>
        </Group>
      </Box>

      <Box style={{ flex: 1, overflow: 'hidden', display: 'flex' }}>
        {pdfPath ? (
          <>
            <ThumbnailPanel
              pdfPath={pdfPath}
              pageCount={pageCount}
              selectedPage={selectedPage}
              onSelectPage={setSelectedPage}
              onToggleSplitPoint={handleToggleSplitPoint}
              outputFiles={outputFiles}
              outputFolder={outputFolder}
              focus={focus}
            />
            <DetailPanel
              pdfPath={pdfPath}
              pageNum={selectedPage}
              pageCount={pageCount}
              onNavigate={setSelectedPage}
            />
          </>
        ) : (
          <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Button onClick={handleOpen}>Open PDF</Button>
          </Box>
        )}
      </Box>
    </Box>
  )
}

import { useState, useCallback } from 'react'
import { PickFolder } from '../../../wailsjs/go/main/App'

export interface OutputFile {
  name: string
  folderOverride?: string
}

// Keyed by firstPage of each output section. firstPage 1 is always present.
type OutputFilesMap = Map<number, OutputFile>

export interface OutputFilesHandle {
  all: OutputFilesMap
  getSplitPoints: () => Set<number>
  toggle: (afterPage: number, prefillName: string) => boolean
  setName: (firstPage: number, name: string) => void
  pickFolderOverride: (firstPage: number) => Promise<void>
  reset: (firstPageName: string) => void
}

export function useOutputFiles(): OutputFilesHandle {
  const [files, setFiles] = useState<OutputFilesMap>(new Map([[1, { name: '' }]]))

  const toggle = (afterPage: number, prefillName: string): boolean => {
    const firstPage = afterPage + 1
    const adding = !files.has(firstPage)
    setFiles(prev => {
      const next = new Map(prev)
      if (next.has(firstPage)) {
        next.delete(firstPage)
      } else {
        next.set(firstPage, { name: prefillName })
      }
      return next
    })
    return adding
  }

  const setName = useCallback((firstPage: number, name: string) => {
    setFiles(prev => {
      const entry = prev.get(firstPage)
      if (!entry) return prev
      return new Map(prev).set(firstPage, { ...entry, name })
    })
  }, [])

  const pickFolderOverride = useCallback(async (firstPage: number) => {
    const folder = await PickFolder()
    if (!folder) return
    setFiles(prev => {
      const entry = prev.get(firstPage)
      if (!entry) return prev
      return new Map(prev).set(firstPage, { ...entry, folderOverride: folder })
    })
  }, [])

  const reset = useCallback((firstPageName: string) => {
    setFiles(new Map([[1, { name: firstPageName }]]))
  }, [])

  const getSplitPoints = () => {
    const result = new Set<number>()
    for (const firstPage of files.keys()) {
      if (firstPage > 1) result.add(firstPage - 1)
    }
    return result
  }

  return {
    all: files,
    getSplitPoints,
    toggle,
    setName,
    pickFolderOverride,
    reset,
  }
}

import { useRef, useState, useEffect, useMemo } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Loader } from '@mantine/core'
import * as pageCache from '../../hooks/pageCache'
import { DEFAULT_WIDTH, DRAG_HANDLE_WIDTH, ITEM_PADDING, PAGE_ASPECT, LABEL_HEIGHT } from '../../constants'
import type { OutputFilesHandle } from './useOutputFiles'

const MIN_WIDTH = 120
const MAX_WIDTH = 480
const GAP_HEIGHT = 16
const HEADER_HEIGHT = 64

type ListItem =
  | { type: 'header'; fileIndex: number; firstPage: number }
  | { type: 'page'; page: number }

function buildItems(pageCount: number, splitPoints: Set<number>): ListItem[] {
  const result: ListItem[] = []
  let fileIndex = 0
  for (let page = 1; page <= pageCount; page++) {
    if (page === 1 || splitPoints.has(page - 1)) {
      result.push({ type: 'header', fileIndex: fileIndex++, firstPage: page })
    }
    result.push({ type: 'page', page })
  }
  return result
}

export interface PendingFocusHandle {
  pendingFocus: { afterPage: number; cursorPos: number } | null
  clear: () => void
}

interface Props {
  pdfPath: string
  pageCount: number
  selectedPage: number
  onSelectPage: (page: number) => void
  onToggleSplitPoint: (afterPage: number) => void
  outputFiles: OutputFilesHandle
  outputFolder: string | null
  focus: PendingFocusHandle
}

export default function SplitThumbnailPanel({
  pdfPath, pageCount, selectedPage, onSelectPage,
  onToggleSplitPoint,
  outputFiles,
  outputFolder,
  focus,
}: Props) {
  const [panelWidth, setPanelWidth] = useState(DEFAULT_WIDTH)
  const [hoveredGap, setHoveredGap] = useState<number | null>(null)

  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const pageItemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING + GAP_HEIGHT

  const splitPoints = useMemo(() => outputFiles.getSplitPoints(), [outputFiles.all])
  const items = useMemo(() => buildItems(pageCount, splitPoints), [pageCount, splitPoints])
  // Ref so the scroll effect can read the current list without depending on it
  // (we don't want to re-scroll every time a split point is toggled).
  const itemsRef = useRef(items)
  itemsRef.current = items

  const scrollRef = useRef<HTMLDivElement>(null)

  const virtualizer = useVirtualizer({
    count: items.length,
    getScrollElement: () => scrollRef.current,
    estimateSize: (index) => items[index]?.type === 'header' ? HEADER_HEIGHT : pageItemHeight,
    overscan: 3,
  })

  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [items.length, pageItemHeight])

  const virtualItems = virtualizer.getVirtualItems()
  pageCache.usePageCacheRender()

  useEffect(() => {
    for (const vItem of virtualItems) {
      const item = items[vItem.index]
      if (item.type === 'page') pageCache.load(pdfPath, item.page, thumbWidth)
    }
  })

  useEffect(() => {
    const index = itemsRef.current.findIndex(item => item.type === 'page' && item.page === selectedPage)
    if (index >= 0) virtualizer.scrollToIndex(index, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return
      if (e.key === 'ArrowLeft') {
        e.preventDefault()
        if (selectedPage > 1) onSelectPage(selectedPage - 1)
      } else if (e.key === 'ArrowRight') {
        e.preventDefault()
        if (selectedPage < pageCount) onSelectPage(selectedPage + 1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [selectedPage, pageCount, onSelectPage])

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = panelWidth
    const clamp = (w: number) => Math.max(MIN_WIDTH, Math.min(MAX_WIDTH, w))
    const onMove = (ev: MouseEvent) => setPanelWidth(clamp(startWidth + ev.clientX - startX))
    const onUp = (ev: MouseEvent) => {
      setPanelWidth(clamp(startWidth + ev.clientX - startX))
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <div style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <div style={{ display: 'flex', flexDirection: 'column', width: panelWidth, height: '100%' }}>
        <div
          ref={scrollRef}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            overflowX: 'hidden',
            background: 'var(--mantine-color-gray-3)',
          }}
        >
          <div style={{ height: virtualizer.getTotalSize(), position: 'relative' }}>
            {virtualItems.map(vItem => {
              const item = items[vItem.index]

              if (item.type === 'header') {
                return (
                  <div
                    key={vItem.key}
                    style={{ position: 'absolute', top: vItem.start, left: 0, width: '100%', height: vItem.size }}
                  >
                    <OutputFileHeader
                      filename={outputFiles.all.get(item.firstPage)?.name ?? ''}
                      onChange={(name) => outputFiles.setName(item.firstPage, name)}
                      firstPage={item.firstPage}
                      focus={focus}
                      folder={outputFiles.all.get(item.firstPage)?.folderOverride ?? outputFolder}
                      onPickFolder={() => outputFiles.pickFolderOverride(item.firstPage)}
                    />
                  </div>
                )
              }

              const page = item.page
              const src = pageCache.getSrc(pdfPath, page)
              const isSelected = page === selectedPage
              const isSplit = splitPoints.has(page)
              const isLastPage = page === pageCount

              return (
                <div
                  key={vItem.key}
                  style={{
                    position: 'absolute',
                    top: vItem.start,
                    left: 0,
                    width: '100%',
                    height: vItem.size,
                    boxSizing: 'border-box',
                  }}
                >
                  {/* Thumbnail */}
                  <div
                    style={{ padding: ITEM_PADDING, paddingBottom: 0, cursor: 'pointer' }}
                    onClick={() => onSelectPage(page)}
                  >
                    <div
                      style={{
                        border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
                        borderRadius: 4,
                        overflow: 'hidden',
                        background: 'var(--mantine-color-gray-1)',
                      }}
                    >
                      {src ? (
                        <img
                          src={src}
                          alt={`Page ${page}`}
                          style={{ width: '100%', display: 'block' }}
                          draggable={false}
                        />
                      ) : (
                        <div style={{ width: '100%', height: thumbHeight, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                          {pageCache.isLoading(pdfPath, page) && <Loader size="xs" />}
                        </div>
                      )}
                    </div>
                    <div
                      style={{
                        textAlign: 'center',
                        fontSize: 11,
                        color: 'var(--mantine-color-gray-7)',
                        height: LABEL_HEIGHT,
                        lineHeight: `${LABEL_HEIGHT}px`,
                      }}
                    >
                      {page}
                    </div>
                  </div>

                  {/* Gap zone between thumbnails */}
                  {!isLastPage && (
                    <GapZone
                      isSplit={isSplit}
                      isHovered={hoveredGap === page}
                      onClick={(e) => { e.stopPropagation(); onToggleSplitPoint(page) }}
                      onMouseEnter={() => setHoveredGap(page)}
                      onMouseLeave={() => setHoveredGap(null)}
                    />
                  )}
                </div>
              )
            })}
          </div>
        </div>
      </div>

      <div
        onMouseDown={startDrag}
        style={{
          width: DRAG_HANDLE_WIDTH,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
          background: 'var(--mantine-color-gray-3)',
        }}
      />
    </div>
  )
}

function OutputFileHeader({
  filename, onChange, firstPage, focus, folder, onPickFolder,
}: {
  filename: string
  onChange: (name: string) => void
  firstPage: number
  focus: PendingFocusHandle
  folder: string | null
  onPickFolder: () => void
}) {
  const shouldFocus = focus.pendingFocus?.afterPage === firstPage - 1
  const cursorPos = focus.pendingFocus?.cursorPos ?? 0
  return (
    <div
      style={{
        margin: `4px ${ITEM_PADDING}px`,
        height: HEADER_HEIGHT - 8,
        padding: '4px 6px',
        background: 'var(--mantine-color-white)',
        border: '1px solid var(--mantine-color-gray-3)',
        borderRadius: 4,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'space-between',
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: 2 }}>
        <input
          ref={(el) => {
            if (el && shouldFocus) {
              el.focus()
              el.setSelectionRange(cursorPos, cursorPos)
              focus.clear()
            }
          }}
          type="text"
          value={filename}
          onChange={(e) => onChange(e.target.value)}
          placeholder="filename"
          style={{
            flex: 1,
            border: 'none',
            outline: 'none',
            background: 'transparent',
            fontSize: 12,
            fontWeight: 500,
            color: 'inherit',
            minWidth: 0,
          }}
        />
        <span style={{ fontSize: 12, color: 'var(--mantine-color-dimmed)', flexShrink: 0 }}>.pdf</span>
      </div>
      <div
        onClick={onPickFolder}
        style={{
          fontSize: 11,
          color: folder ? 'var(--mantine-color-gray-6)' : 'var(--mantine-color-dimmed)',
          cursor: 'pointer',
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
        }}
      >
        {folder ?? 'Choose folder…'}
      </div>
    </div>
  )
}

interface GapZoneProps {
  isSplit: boolean
  isHovered: boolean
  onClick: (e: React.MouseEvent) => void
  onMouseEnter: () => void
  onMouseLeave: () => void
}

function GapZone({ isSplit, isHovered, onClick, onMouseEnter, onMouseLeave }: GapZoneProps) {
  const bg = isSplit
    ? 'var(--mantine-color-blue-0)'
    : isHovered
    ? 'var(--mantine-color-gray-2)'
    : undefined

  return (
    <div
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      style={{
        height: GAP_HEIGHT,
        background: bg,
        display: 'flex',
        alignItems: 'center',
        paddingLeft: ITEM_PADDING,
        paddingRight: ITEM_PADDING,
        cursor: 'pointer',
      }}
    >
      {isSplit && (
        <div style={{ flex: 1, height: 2, background: 'var(--mantine-color-blue-5)', borderRadius: 1 }} />
      )}
      {!isSplit && isHovered && (
        <div style={{ flex: 1, height: 0, borderTop: '1px dashed var(--mantine-color-gray-5)' }} />
      )}
    </div>
  )
}

